import{_ as t,o as a,c as l,ag as e}from"./chunks/framework.DtEl18Xn.js";const o="/getbiji-docs-v3/images/BM05b2CPioXOe7xugHEcfN5anyh.png",s="/getbiji-docs-v3/images/UzWwbk1gfoL7dtx5BtMcWy3knae.png",r="/getbiji-docs-v3/images/L7aVbPrxloNh7HxQqZncttGSnth.png",n="/getbiji-docs-v3/images/F5sFbIjAGokyXixvn5wcobldnCg.png",p="/getbiji-docs-v3/images/AhMjbjLpZof5aCxLkDScMwfGnof.png",c="/getbiji-docs-v3/images/T9GTbfdntoa45exLnVZcFDSVnFg.png",f=JSON.parse('{"title":"手机内录-边听边记","description":"","frontmatter":{"title":"手机内录-边听边记","category":" 如何快速上手记笔记","lastUpdated":"2026-03-14T14:54:27.256Z"},"headers":[],"relativePath":"-如何快速上手记笔记/手机内录-边听边记.md","filePath":"-如何快速上手记笔记/手机内录-边听边记.md"}'),_={name:"-如何快速上手记笔记/手机内录-边听边记.md"};function g(m,i,d,h,u,b){return a(),l("div",null,[...i[0]||(i[0]=[e('<h1 id="手机内录-边听边记" tabindex="-1">手机内录-边听边记 <a class="header-anchor" href="#手机内录-边听边记" aria-label="Permalink to &quot;手机内录-边听边记&quot;">​</a></h1><p><strong>手机内录，边听边记，一气呵成！</strong></p><p>自动捕获手机播放的声音，AI同步转写文字，让你在听的同时就把重点内容记下来。</p><p><strong>适用场景</strong></p><ul><li>线上学习：线上直播课程、讲座内容轻松记录</li><li>视频记录：生成视频逐字稿 + 要点总结</li><li>播客整理：语音+文字双轨保存，随时回顾不遗漏</li><li>区分说话人：多个说话人，可以自动区分每个说话人内容</li></ul><p><strong>不适用的场景：</strong></p><ul><li>录制拨打电话、语音通话、微信 QQ 通话</li><li>腾讯/飞书/钉钉会议等场景</li><li>带耳机等外部播放设备时也无法正常录制</li></ul><h1 id="app端-使用说明" tabindex="-1">APP端-使用说明 <a class="header-anchor" href="#app端-使用说明" aria-label="Permalink to &quot;APP端-使用说明&quot;">​</a></h1><ol><li>打开 APP，点击首页底部「录音」按钮，选择「手机内录」</li><li>同意 Get 笔记使用手机录屏权限，然后点击红色按钮“开始录制”</li><li>请注意，安卓设备使用手机内录，需要开启 录屏权限 + 通知权限</li><li>然后，去其他 APP 打开你想录制的内容（如播客、B站直播等）开始播放</li><li>回到 Get 笔记 APP 后，录制页面会有实时转录的文字展示出来，即表示已经在进行录制了</li><li>最终录制结束后，AI 会自动对音频转写并总结整理</li></ol><h2 id="录制时长" tabindex="-1">录制时长 <a class="header-anchor" href="#录制时长" aria-label="Permalink to &quot;录制时长&quot;">​</a></h2><ul><li>普通用户，单次可以录制 1 小时，不限次数</li><li>会员用户，<strong>单次可以录制 3 小时，不限次数</strong></li></ul><h4 id="特别说明" tabindex="-1">特别说明 <a class="header-anchor" href="#特别说明" aria-label="Permalink to &quot;特别说明&quot;">​</a></h4><ul><li><em>手机内录仅通过手机内部声音进行转写，不会录制你的手机屏幕和保存任何视频；</em></li><li><em>如果遇到中断暂停等情况，可以点击录音按钮继续录制。</em><img src="'+o+'" alt=""></li></ul><p><img src="'+s+'" alt=""></p><p><img src="'+r+'" alt=""></p><p><img src="'+n+'" alt=""></p><p><img src="'+p+'" alt=""></p><p><img src="'+c+'" alt=""></p>',18)])])}const x=t(_,[["render",g]]);export{f as __pageData,x as default};
